// PREVENTION: process x items WITHOUT materializing them all.
// Same x that OOM'd when we returned x ITEMS — here we only keep a running
// total and return ONE small item, so the heap never fills.
const j = $input.first().json;
const x = Number(j.query?.x ?? 1000);
let checksum = 0;
for (let i = 0; i < x; i++) { checksum += i % 7; }
return [{ json: { processed: x, checksum } }];
